import { updateMode } from './devvit-global.js';
/** @internal */
export function initWebViewMode() {
    addEventListener('message', onWebViewMessage);
}
/** @internal */
export function onWebViewMessage(ev) {
    if (ev.data?.type !== 'devvit-message')
        return;
    if (!ev.data?.data?.immersiveModeEvent)
        return;
    updateMode(ev.data.data.immersiveModeEvent.immersiveMode);
}
